code.C:
#include <stdio.h>
int main(){
    const double side=4.5;
    const int T=1;
    for(int i=0;i<T;++i){
        double area=side*side;
        double per=4.0*side;
        printf("%g\n%.1f\n",area,per);
    }
    return 0;
}

